// --- Sync Manager (orchestrates periodic sync) ---

class SyncManager {
  final ApiClient _apiClient;
  Timer? _syncTimer;
  DateTime? _lastSyncedAt;
  bool _isSyncing = false;

  final StreamController<SyncStatus> _statusController =
      StreamController<SyncStatus>.broadcast();

  Stream<SyncStatus> get statusStream => _statusController.stream;

  SyncManager({required ApiClient apiClient}) : _apiClient = apiClient;

  void dispose() {
    stopPeriodicSync();
    _statusController.close();
  }

  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    stopPeriodicSync();
    _syncTimer = Timer.periodic(interval, (_) => performSync());
  }

  void stopPeriodicSync() {
    _syncTimer?.cancel();
    _syncTimer = null;
  }

  Future<SyncResult?> performSync({List<SyncData>? localChanges}) async {
    if (_isSyncing) return null;
    _isSyncing = true;
    _statusController.add(SyncStatus.syncing);

    try {
      final result = await _apiClient.syncData(
        localChanges: localChanges ?? [],
        lastSyncedAt: _lastSyncedAt,
      );

      _lastSyncedAt = result.syncedAt;
      _statusController.add(SyncStatus.completed);
      return result;
    } on NetworkException {
      _statusController.add(SyncStatus.offline);
      return null;
    } on UnauthorizedException {
      _statusController.add(SyncStatus.authError);
      stopPeriodicSync();
      return null;
    } catch (e) {
      _statusController.add(SyncStatus.error);
      return null;
    } finally {
      _isSyncing = false;
    }
  }
}

enum SyncStatus {
  idle,
  syncing,
  completed,
  error,
  offline,
  authError,
}

// --- Example usage (main) ---

Future<void> main() async {
  final apiClient = ApiClient();

  try {
    // 1. Login
    print('Logging in...');
    final token = await apiClient.login(
      email: 'user@example.com',
      password: 'securePassword123',
    );
    print('Logged in. Token expires at: ${token.expiresAt}');

    // 2. Get user profile
    print('Fetching profile...');
    final profile = await apiClient.getProfile();
    print('Profile: ${profile.name} (${profile.email})');

    // 3. Update profile
    print('Updating profile...');
    final updatedProfile = await apiClient.updateProfile(name: 'New Name');
    print('Updated profile name: ${updatedProfile.name}');

    // 4. Data sync
    print('Starting sync...');
    final syncManager = SyncManager(apiClient: apiClient);

    syncManager.statusStream.listen((status) {
      print('Sync status: $status');
    });

    final localChanges = [
      SyncData(
        id: 'item-1',
        type: 'note',
        payload: {'title': 'My Note', 'body': 'Hello world'},
        updatedAt: DateTime.now(),
      ),
    ];

    final syncResult = await syncManager.performSync(
      localChanges: localChanges,
    );

    if (syncResult != null) {
      print('Sync complete. Pulled ${syncResult.pulled.length} items, '
          'pushed ${syncResult.pushedCount} items.');
    }

    // 5. Start periodic sync
    syncManager.startPeriodicSync(interval: const Duration(minutes: 5));

    // 6. Pull changes since last sync
    final changes = await apiClient.pullChanges(since: syncResult?.syncedAt);
    print('Pulled ${changes.length} new changes.');

    // Cleanup
    syncManager.stopPeriodicSync();
    syncManager.dispose();

    // 7. Logout
    await apiClient.logout();
    print('Logged out.');
  } on ApiException catch (e) {
    print('API error: $e');
  } on NetworkException catch (e) {
    print('Network error: $e');
  } finally {
    apiClient.dispose();
  }
}